import{_ as t,o as e,c as i,a2 as o}from"./chunks/framework.DZrHScmQ.js";const p=JSON.parse('{"title":"Public Handbook and Private Context Split","description":"","frontmatter":{"status":"Draft","owner":"待指定","scope":"organization","last_reviewed":"2026-06-15T00:00:00.000Z"},"headers":[],"relativePath":"ai-native/case-studies/public-private-context-split.md","filePath":"ai-native/case-studies/public-private-context-split.md"}'),l={name:"ai-native/case-studies/public-private-context-split.md"};function d(r,a,n,c,s,h){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="public-handbook-and-private-context-split" tabindex="-1">Public Handbook and Private Context Split <a class="header-anchor" href="#public-handbook-and-private-context-split" aria-label="Permalink to &quot;Public Handbook and Private Context Split&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>Owner：待指定</strong></p><h2 id="背景与目标" tabindex="-1">背景与目标 <a class="header-anchor" href="#背景与目标" aria-label="Permalink to &quot;背景与目标&quot;">​</a></h2><p>团队需要沉淀 AI 协作经验，但不是所有上下文都适合进入公共 Handbook。</p><p>目标：把长期、脱敏、可复用的知识放到 Handbook；把个人偏好、原始观察、客户信息、本机路径和密钥留在私有 Context Workspace。</p><h2 id="原有方式" tabindex="-1">原有方式 <a class="header-anchor" href="#原有方式" aria-label="Permalink to &quot;原有方式&quot;">​</a></h2><p>如果不分层，容易出现两种问题：</p><ul><li>公共文档夹带私密上下文。</li><li>有价值经验只留在个人记忆里，团队无法复用。</li></ul><h2 id="引入的实践" tabindex="-1">引入的实践 <a class="header-anchor" href="#引入的实践" aria-label="Permalink to &quot;引入的实践&quot;">​</a></h2><ul><li><code>SOURCE_OF_TRUTH.md</code> 定义 Handbook、项目文档、仓库文档和代码真源。</li><li><code>WORKSPACE.md</code> 定义内容路由。</li><li><code>ai-native/context-system/</code> 定义 L0-L3 上下文层级。</li><li><code>public-private-boundary.md</code> 明确哪些内容不能进入公共仓库。</li></ul><h2 id="责任分配" tabindex="-1">责任分配 <a class="header-anchor" href="#责任分配" aria-label="Permalink to &quot;责任分配&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>责任</th></tr></thead><tbody><tr><td>贡献者</td><td>提交前脱敏，区分事实和经验</td></tr><tr><td>Reviewer</td><td>检查隐私、真源和适用范围</td></tr><tr><td>Agent</td><td>帮助整理，但不得把私有记忆直接写入公共文档</td></tr></tbody></table><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to &quot;结果&quot;">​</a></h2><p>当前 Handbook 已明确：</p><ul><li>公共仓库不放密钥、客户数据、本机路径、私密会议记录。</li><li>原始 Observation 不直接晋升为 Standard。</li><li>长期知识需要证据、适用范围和复审。</li></ul><h2 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h2><ul><li>私有 Context Workspace 的实际执行仍依赖个人习惯。</li><li>目前还没有自动扫描所有隐私风险。</li><li>哪些经验值得晋升，仍需要人工判断。</li></ul><h2 id="可复用结论" tabindex="-1">可复用结论 <a class="header-anchor" href="#可复用结论" aria-label="Permalink to &quot;可复用结论&quot;">​</a></h2><ul><li>公共 Handbook 应保存“可复用结论”，不是原始记忆池。</li><li>私密上下文可以帮助个人工作，但进入组织知识前必须脱敏和复核。</li><li>Agent 写文档时，先判断内容层级比直接总结更重要。</li></ul><h2 id="证据" tabindex="-1">证据 <a class="header-anchor" href="#证据" aria-label="Permalink to &quot;证据&quot;">​</a></h2><ul><li><code>SOURCE_OF_TRUTH.md</code></li><li><code>WORKSPACE.md</code></li><li><code>ai-native/context-system/README.md</code></li><li><code>ai-native/context-system/public-private-boundary.md</code></li></ul>',22)])])}const b=t(l,[["render",d]]);export{p as __pageData,b as default};
